\set ON_ERROR_STOP on

CREATE OR REPLACE FUNCTION public.planning_concurrency_apply(
 _batch uuid,_key text,_task uuid,_cleaner uuid,_date date,_start time,_end time
) RETURNS jsonb
LANGUAGE plpgsql SECURITY DEFINER SET search_path=pg_catalog,public AS $$
DECLARE i jsonb; h text;
BEGIN
 i:=jsonb_build_array(jsonb_build_object(
  'task_id',_task,'expected_planning_version',0,
  'expected_status','pending','expected_cleaner_ids','[]'::jsonb,
  'date',_date,'start_time',_start,'end_time',_end,
  'cleaner_ids',jsonb_build_array(_cleaner)));
 h:=public.planning_batch_request_hash('12000000-0000-0000-0000-000000000001',NULL,NULL,'best_effort',i);
 PERFORM set_config('request.jwt.claim.sub','22000000-0000-0000-0000-000000000001',true);
 RETURN public.apply_planning_batch(_batch,_key,'12000000-0000-0000-0000-000000000001',NULL,NULL,h,'best_effort',i);
END $$;
